#[test]
fn test_u256_to_address_conversion() {
    let executor_address = address!("9858EfFD232B4033E47d90003D41EC34EcaEda94");

    // Create U256 with address in last 20 bytes (Solidity convention)
    let mut bytes = [0u8; 32];
    bytes[12..].copy_from_slice(executor_address.as_slice());
    let executor_u256 = U256::from_be_bytes(bytes);

    // Verify conversion back
    let recovered = Address::from_slice(&executor_u256.to_be_bytes::<32>()[12..]);
    assert_eq!(recovered, executor_address);
}

